{ Launch Interceptor Program — DECIDE and REALCOMPARE (K&L, 1986) }

unit lipdecide;

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

{ --- six-significant-figure normalisation (used by REALCOMPARE) --- }

{ Internal compare without REALCOMPARE to avoid infinite recursion. }
function REALCOMPARE_WIP(A, B: real): COMPTYPE;
begin
  if A < B then
    REALCOMPARE_WIP := LT
  else if A > B then
    REALCOMPARE_WIP := GT
  else
    REALCOMPARE_WIP := EQ;
end;

function Round6SigFigs(x: real): real;
var
  ax, t, s: real;
  e: longint;
  m: int64;
begin
  { REALCOMPARE_WIP(0) only for the zero test path }
  if REALCOMPARE_WIP(x, 0) = EQ then
  begin
    Round6SigFigs := 0;
    exit;
  end;
  s := 1.0;
  if x < 0.0 then
    s := -1.0;
  ax := abs(x);
  e := Trunc(floor(ln(ax) / ln(10.0)));
  t := ax * intpower(10.0, 5 - e);
  m := round(t);
  if m >= 1000000 then
  begin
    e := e + 1;
    t := ax * intpower(10.0, 5 - e);
    m := round(t);
  end;
  if m = 0 then
    Round6SigFigs := 0.0
  else
    Round6SigFigs := s * m * intpower(10.0, e - 5);
end;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  ra, rb: real;
begin
  ra := Round6SigFigs(A);
  rb := Round6SigFigs(B);
  if ra < rb then
    REALCOMPARE := LT
  else if ra > rb then
    REALCOMPARE := GT
  else
    REALCOMPARE := EQ;
end;

{ --- geometry helpers: distances use real math; final ordering via REALCOMPARE --- }

function SqrReal(x: real): real; inline;
begin
  SqrReal := x * x;
end;

function Dist2(ax, ay, bx, by: real): real;
begin
  Dist2 := sqrt(SqrReal(bx - ax) + SqrReal(by - ay));
end;

function Cross2(ax, ay, bx, by, cx, cy: real): real;
begin
  Cross2 := (bx - ax) * (cy - ay) - (by - ay) * (cx - ax);
end;

{ Twice the signed area of triangle (a,b,c) }
function TriArea2(ax, ay, bx, by, cx, cy: real): real;
begin
  TriArea2 := abs(Cross2(ax, ay, bx, by, cx, cy));
end;

{ Smallest circle covering three points: obtuse → half longest side; else circumcircle. }
function MinCircleRadius3(ax, ay, bx, by, cx, cy: real): real;
var
  e1, e2, e3: real;
  u, v, w, tswp: real;
  A2: real;
  sumSqrOther: real;
begin
  e1 := Dist2(ax, ay, bx, by);
  e2 := Dist2(bx, by, cx, cy);
  e3 := Dist2(cx, cy, ax, ay);
  u := e1;
  v := e2;
  w := e3;
  if REALCOMPARE(v, u) = GT then
  begin
    tswp := u;
    u := v;
    v := tswp;
  end;
  if REALCOMPARE(w, u) = GT then
  begin
    tswp := u;
    u := w;
    w := tswp;
  end;
  if REALCOMPARE(w, v) = GT then
  begin
    tswp := v;
    v := w;
    w := tswp;
  end;
  A2 := TriArea2(ax, ay, bx, by, cx, cy);
  if REALCOMPARE(A2, 0) = EQ then
  begin
    MinCircleRadius3 := u / 2.0;
    exit;
  end;
  sumSqrOther := SqrReal(v) + SqrReal(w);
  { Strictly obtuse: opposite u }
  if REALCOMPARE(sumSqrOther, SqrReal(u)) = LT then
  begin
    MinCircleRadius3 := u / 2.0;
    exit;
  end;
  MinCircleRadius3 := (e1 * e2 * e3) / (2.0 * A2);
end;

function PointLineDist(pqx, pqy, ax, ay, bx, by: real): real;
var
  len2: real;
  dx, dy, num: real;
begin
  dx := bx - ax;
  dy := by - ay;
  len2 := SqrReal(dx) + SqrReal(dy);
  if REALCOMPARE(len2, 0) = EQ then
  begin
    PointLineDist := Dist2(pqx, pqy, ax, ay);
    exit;
  end;
  num := abs(dx * (pqy - ay) - dy * (pqx - ax));
  PointLineDist := num / sqrt(len2);
end;

function GetQuad(x, y: real): longint;
begin
  if (REALCOMPARE(x, 0) = EQ) and (REALCOMPARE(y, 0) = EQ) then
    GetQuad := 1
  else if (REALCOMPARE(y, 0) = EQ) and (REALCOMPARE(x, 0) = LT) then
    GetQuad := 2
  else if (REALCOMPARE(y, 0) = EQ) and (REALCOMPARE(x, 0) = GT) then
    GetQuad := 1
  else if (REALCOMPARE(x, 0) = EQ) and (REALCOMPARE(y, 0) = GT) then
    GetQuad := 1
  else if (REALCOMPARE(x, 0) = EQ) and (REALCOMPARE(y, 0) = LT) then
    GetQuad := 3
  else if (REALCOMPARE(x, 0) = GT) and (REALCOMPARE(y, 0) = GT) then
    GetQuad := 1
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) = GT) then
    GetQuad := 2
  else if (REALCOMPARE(x, 0) = LT) and (REALCOMPARE(y, 0) = LT) then
    GetQuad := 3
  else
    GetQuad := 4; { x>0, y<0 }
end;

function CountDistinctQuadsInWindow(Start: longint; qpts: longint): longint;
var
  p, c: longint;
  u: array[1..4] of boolean;
  n: longint;
begin
  u[1] := False;
  u[2] := False;
  u[3] := False;
  u[4] := False;
  for p := 0 to qpts - 1 do
  begin
    c := GetQuad(X[Start + p], Y[Start + p]);
    u[c] := True;
  end;
  n := 0;
  for c := 1 to 4 do
    if u[c] then
      n := n + 1;
  CountDistinctQuadsInWindow := n;
end;

{ --- LICs 1..15 --- }

function LIC1: boolean;
var
  i: longint;
  d: real;
begin
  LIC1 := False;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := Dist2(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      LIC1 := True;
      exit;
    end;
  end;
end;

function LIC2: boolean;
var
  i: longint;
  r: real;
begin
  LIC2 := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    r := MinCircleRadius3(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      LIC2 := True;
      exit;
    end;
  end;
end;

function LIC3: boolean;
var
  i: longint;
  x1, y1, x2, y2, x3, y3: real;
  vx, vy, wx, wy, len1, len2, c, ang: real;
begin
  LIC3 := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    x1 := X[i];
    y1 := Y[i];
    x2 := X[i + 1];
    y2 := Y[i + 1];
    x3 := X[i + 2];
    y3 := Y[i + 2];
    { vertex at 2: vectors 2->1 and 2->3 }
    vx := x1 - x2;
    vy := y1 - y2;
    wx := x3 - x2;
    wy := y3 - y2;
    len1 := sqrt(SqrReal(vx) + SqrReal(vy));
    len2 := sqrt(SqrReal(wx) + SqrReal(wy));
    if (REALCOMPARE(len1, 0) = EQ) or (REALCOMPARE(len2, 0) = EQ) then
      Continue;
    c := (vx * wx + vy * wy) / (len1 * len2);
    if c < -1.0 then
      c := -1.0
    else if c > 1.0 then
      c := 1.0;
    ang := arccos(c);
    if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
      (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
    begin
      LIC3 := True;
      exit;
    end;
  end;
end;

function LIC4: boolean;
var
  i: longint;
  a2: real;
begin
  LIC4 := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    a2 := TriArea2(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(0.5 * a2, PARAMETERS.AREA1) = GT then
    begin
      LIC4 := True;
      exit;
    end;
  end;
end;

function LIC5: boolean;
var
  i: longint;
  n: longint;
  qp, nq: longint;
begin
  qp := LongInt(PARAMETERS.Q_PTS);
  nq := LongInt(PARAMETERS.QUADS);
  LIC5 := False;
  for i := 1 to NUMPOINTS - qp + 1 do
  begin
    n := CountDistinctQuadsInWindow(i, qp);
    if n > nq then
    begin
      LIC5 := True;
      exit;
    end;
  end;
end;

function LIC6: boolean;
var
  i: longint;
begin
  LIC6 := False;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i + 1] - X[i], 0) = LT then
    begin
      LIC6 := True;
      exit;
    end;
  end;
end;

function LIC7: boolean;
var
  s, t: longint;
  n: longint;
  ax, ay, bx, by: real;
  d: real;
  firstLastSame: boolean;
  np: longint;
begin
  if NUMPOINTS < 3 then
  begin
    LIC7 := False;
    exit;
  end;
  np := LongInt(PARAMETERS.N_PTS);
  LIC7 := False;
  for s := 1 to NUMPOINTS - np + 1 do
  begin
    ax := X[s];
    ay := Y[s];
    t := s + np - 1;
    bx := X[t];
    by := Y[t];
    firstLastSame :=
      (REALCOMPARE(ax, bx) = EQ) and (REALCOMPARE(ay, by) = EQ);
    if firstLastSame then
    begin
      for n := s to t do
      begin
        if n = s then
          Continue;
        d := Dist2(X[n], Y[n], ax, ay);
        if REALCOMPARE(d, PARAMETERS.DIST) = GT then
        begin
          LIC7 := True;
          exit;
        end;
      end;
    end
    else
    begin
      for n := s to t do
      begin
        d := PointLineDist(X[n], Y[n], ax, ay, bx, by);
        if REALCOMPARE(d, PARAMETERS.DIST) = GT then
        begin
          LIC7 := True;
          exit;
        end;
      end;
    end;
  end;
end;

function LIC8: boolean;
var
  i, j, gap: longint;
  d: real;
  kp: longint;
begin
  if NUMPOINTS < 3 then
  begin
    LIC8 := False;
    exit;
  end;
  kp := LongInt(PARAMETERS.K_PTS);
  gap := kp + 1; { j = i + K_PTS + 1: exactly K_PTS points between }
  LIC8 := False;
  for i := 1 to NUMPOINTS - gap do
  begin
    j := i + gap;
    d := Dist2(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      LIC8 := True;
      exit;
    end;
  end;
end;

function LIC9: boolean;
var
  i, j, k, ap, bp: longint;
  r: real;
begin
  if NUMPOINTS < 5 then
  begin
    LIC9 := False;
    exit;
  end;
  ap := LongInt(PARAMETERS.A_PTS);
  bp := LongInt(PARAMETERS.B_PTS);
  LIC9 := False;
  for i := 1 to NUMPOINTS - 2 - ap - bp do
  begin
    j := i + ap + 1;
    k := j + bp + 1;
    r := MinCircleRadius3(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      LIC9 := True;
      exit;
    end;
  end;
end;

function LIC10: boolean;
var
  i: longint;
  j, k: longint;
  cp, dp: longint;
  x1, y1, x2, y2, x3, y3: real;
  vx, vy, wx, wy, len1, len2, c, ang: real;
begin
  if NUMPOINTS < 5 then
  begin
    LIC10 := False;
    exit;
  end;
  cp := LongInt(PARAMETERS.C_PTS);
  dp := LongInt(PARAMETERS.D_PTS);
  LIC10 := False;
  for i := 1 to NUMPOINTS - 2 - cp - dp do
  begin
    j := i + cp + 1;
    k := j + dp + 1;
    x1 := X[i];
    y1 := Y[i];
    x2 := X[j];
    y2 := Y[j];
    x3 := X[k];
    y3 := Y[k];
    vx := x1 - x2;
    vy := y1 - y2;
    wx := x3 - x2;
    wy := y3 - y2;
    len1 := sqrt(SqrReal(vx) + SqrReal(vy));
    len2 := sqrt(SqrReal(wx) + SqrReal(wy));
    if (REALCOMPARE(len1, 0) = EQ) or (REALCOMPARE(len2, 0) = EQ) then
      Continue;
    c := (vx * wx + vy * wy) / (len1 * len2);
    if c < -1.0 then
      c := -1.0
    else if c > 1.0 then
      c := 1.0;
    ang := arccos(c);
    if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
      (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
    begin
      LIC10 := True;
      exit;
    end;
  end;
end;

function LIC11: boolean;
var
  i, j, k: longint;
  ep, fp: longint;
  a2: real;
begin
  if NUMPOINTS < 5 then
  begin
    LIC11 := False;
    exit;
  end;
  ep := LongInt(PARAMETERS.E_PTS);
  fp := LongInt(PARAMETERS.F_PTS);
  LIC11 := False;
  for i := 1 to NUMPOINTS - 2 - ep - fp do
  begin
    j := i + ep + 1;
    k := j + fp + 1;
    a2 := TriArea2(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(0.5 * a2, PARAMETERS.AREA1) = GT then
    begin
      LIC11 := True;
      exit;
    end;
  end;
end;

function LIC12: boolean;
var
  i, j, gp, gap: longint;
begin
  if NUMPOINTS < 3 then
  begin
    LIC12 := False;
    exit;
  end;
  gp := LongInt(PARAMETERS.G_PTS);
  gap := gp + 1;
  LIC12 := False;
  for i := 1 to NUMPOINTS - gap do
  begin
    j := i + gap;
    if REALCOMPARE(X[j] - X[i], 0) = LT then
    begin
      LIC12 := True;
      exit;
    end;
  end;
end;

function LIC13: boolean;
var
  i, j, gap, kp: longint;
  d: real;
  gtL1, ltL2: boolean;
begin
  if NUMPOINTS < 3 then
  begin
    LIC13 := False;
    exit;
  end;
  kp := LongInt(PARAMETERS.K_PTS);
  gap := kp + 1;
  gtL1 := False;
  ltL2 := False;
  for i := 1 to NUMPOINTS - gap do
  begin
    j := i + gap;
    d := Dist2(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      gtL1 := True;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
      ltL2 := True;
  end;
  LIC13 := gtL1 and ltL2;
end;

function LIC14: boolean;
var
  i, j, k, ap, bp: longint;
  r: real;
  p1, p2: boolean;
begin
  if NUMPOINTS < 5 then
  begin
    LIC14 := False;
    exit;
  end;
  ap := LongInt(PARAMETERS.A_PTS);
  bp := LongInt(PARAMETERS.B_PTS);
  p1 := False;
  p2 := False;
  for i := 1 to NUMPOINTS - 2 - ap - bp do
  begin
    j := i + ap + 1;
    k := j + bp + 1;
    r := MinCircleRadius3(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
      p1 := True;
    if (REALCOMPARE(r, PARAMETERS.RADIUS2) = LT) or (REALCOMPARE(r, PARAMETERS.RADIUS2) = EQ) then
      p2 := True;
  end;
  LIC14 := p1 and p2;
end;

function LIC15: boolean;
var
  i, j, k, ep, fp: longint;
  a2, halfa: real;
  p1, p2: boolean;
begin
  if NUMPOINTS < 5 then
  begin
    LIC15 := False;
    exit;
  end;
  ep := LongInt(PARAMETERS.E_PTS);
  fp := LongInt(PARAMETERS.F_PTS);
  p1 := False;
  p2 := False;
  for i := 1 to NUMPOINTS - 2 - ep - fp do
  begin
    j := i + ep + 1;
    k := j + fp + 1;
    a2 := TriArea2(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    halfa := 0.5 * a2;
    if REALCOMPARE(halfa, PARAMETERS.AREA1) = GT then
      p1 := True;
    if REALCOMPARE(halfa, PARAMETERS.AREA2) = LT then
      p2 := True;
  end;
  LIC15 := p1 and p2;
end;

procedure SetCMV;
begin
  CMV[1] := LIC1;
  CMV[2] := LIC2;
  CMV[3] := LIC3;
  CMV[4] := LIC4;
  CMV[5] := LIC5;
  CMV[6] := LIC6;
  CMV[7] := LIC7;
  CMV[8] := LIC8;
  CMV[9] := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;
end;

procedure SetPUMOffDiag;
var
  i, j: longint;
begin
  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
      begin
        case LCM[i, j] of
          NOTUSED:
            PUM[i, j] := True;
          ANDD:
            PUM[i, j] := CMV[i] and CMV[j];
          ORR:
            PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
end;

procedure SetFUV;
var
  i, j: longint;
  allrow: boolean;
begin
  for i := 1 to 15 do
  begin
    if PUM[i, i] = False then
      FUV[i] := True
    else
    begin
      allrow := True;
      for j := 1 to 15 do
        if PUM[i, j] = False then
        begin
          allrow := False;
          break;
        end;
      FUV[i] := allrow;
    end;
  end;
end;

procedure SetLaunch;
var
  i: longint;
begin
  LAUNCH := True;
  for i := 1 to 15 do
    if FUV[i] = False then
    begin
      LAUNCH := False;
      break;
    end;
end;

procedure DECIDE;
begin
  SetCMV;
  SetPUMOffDiag;
  SetFUV;
  SetLaunch;
end;

end.
